// Package testutils provides shared helpers for tests and acceptance demos
// that need a clean ddx-initialized git repo without polluting the main DDx
// project. The canonical entry point is NewFixtureRepo, which wraps
// scripts/build-fixture-repo.sh and auto-cleans via t.Cleanup.
package testutils

import (
	"os"
	"os/exec"
	"path/filepath"
	"sync"
	"testing"
)

// fixtureRepoBaseName is the leaf directory name given to every fixture
// project. It must satisfy the bead-identifier charset (^[a-zA-Z0-9-]+$,
// see internal/bead/id.go), because the bead prefix is derived from the git
// root's basename — a t.TempDir() leaf such as "001" would be numeric-only but
// the surrounding test-name path can contain characters (e.g. "_") that are
// rejected by `ddx bead create`. Nesting a fixed safe name under t.TempDir()
// guarantees a valid prefix regardless of the test name.
const fixtureRepoBaseName = "ddxfixture"

// NewFixtureRepo builds a clean ddx-initialized git repo for the given profile
// (minimal, standard, multi-project, federated) and returns its path. The repo
// is created under t.TempDir() so it is removed automatically when the test
// finishes (the auto-clean promised in scripts/build-fixture-repo.md).
//
// For minimal/standard the returned path is the project root; for
// multi-project/federated it is the parent dir whose sub-projects live
// underneath (proj-a, proj-b / hub, spoke).
//
// The ddx binary used for seeding is resolved via DDxBinary. Global and system
// git config are neutralized for the seeding subprocess so a developer box's
// commit.gpgsign (which points at a host-specific signer) does not break the
// fixture's own commits; repo-local commit.gpgsign is additionally disabled on
// each created project so subsequent ddx commits in the test never attempt to
// sign.
func NewFixtureRepo(t *testing.T, profile string) string {
	t.Helper()

	bin := DDxBinary(t)
	dest := filepath.Join(t.TempDir(), fixtureRepoBaseName)
	script := filepath.Join(repoRoot(t), "scripts", "build-fixture-repo.sh")

	emptyGlobalCfg := filepath.Join(t.TempDir(), "gitconfig-global")
	if err := os.WriteFile(emptyGlobalCfg, nil, 0o644); err != nil {
		t.Fatalf("write neutral global git config: %v", err)
	}

	cmd := exec.Command("bash", script, dest, "--profile", profile)
	cmd.Env = append(os.Environ(),
		"DDX_BIN="+bin,
		"GIT_CONFIG_GLOBAL="+emptyGlobalCfg,
		"GIT_CONFIG_SYSTEM=/dev/null",
	)
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("build-fixture-repo.sh failed (profile=%s): %v\n%s", profile, err, out)
	}

	for _, dir := range fixtureProjectDirs(dest, profile) {
		gc := exec.Command("git", "-C", dir, "config", "commit.gpgsign", "false")
		gc.Env = append(os.Environ(), "GIT_CONFIG_SYSTEM=/dev/null")
		if out, err := gc.CombinedOutput(); err != nil {
			t.Fatalf("disable commit.gpgsign in %s: %v\n%s", dir, err, out)
		}
	}

	return dest
}

// fixtureProjectDirs returns the per-project git roots created for a profile,
// so repo-local config can be applied to each.
func fixtureProjectDirs(dest, profile string) []string {
	switch profile {
	case "multi-project":
		return []string{filepath.Join(dest, "proj-a"), filepath.Join(dest, "proj-b")}
	case "federated":
		return []string{filepath.Join(dest, "hub"), filepath.Join(dest, "spoke")}
	default:
		return []string{dest}
	}
}

var (
	builtBinaryOnce sync.Once
	builtBinaryPath string
	builtBinaryErr  error
)

// DDxBinary resolves a ddx binary for fixture seeding and subprocess tests. It
// prefers $DDX_BIN, then `ddx` on PATH, and otherwise lazily builds one from
// cli/ once per process. The built binary lives in an os.MkdirTemp dir that
// outlives any single test so concurrent fixtures can share it.
func DDxBinary(t *testing.T) string {
	t.Helper()
	if env := os.Getenv("DDX_BIN"); env != "" {
		if _, err := os.Stat(env); err == nil {
			return env
		}
	}
	if p, err := exec.LookPath("ddx"); err == nil {
		return p
	}
	return BuildDDxBinary(t)
}

// BuildDDxBinary builds the ddx binary from the current cli/ source tree once
// per process and returns its path. Tests that must exercise the current source
// (rather than a possibly-stale `ddx` on PATH) should build with this and pin it
// via t.Setenv("DDX_BIN", ...) so NewFixtureRepo seeds with the same binary. The
// binary lives in an os.MkdirTemp dir that outlives any single test.
func BuildDDxBinary(t *testing.T) string {
	t.Helper()
	builtBinaryOnce.Do(func() {
		dir, err := os.MkdirTemp("", "ddx-fixture-bin-*")
		if err != nil {
			builtBinaryErr = err
			return
		}
		out := filepath.Join(dir, "ddx")
		build := exec.Command("go", "build", "-buildvcs=false", "-o", out, ".")
		build.Dir = cliDir(t)
		if combined, err := build.CombinedOutput(); err != nil {
			builtBinaryErr = err
			t.Logf("go build ddx from source failed:\n%s", combined)
			return
		}
		builtBinaryPath = out
	})
	if builtBinaryErr != nil {
		t.Fatalf("build ddx binary from source: %v", builtBinaryErr)
	}
	return builtBinaryPath
}

// cliDir walks up from the test's working directory to the directory that
// holds go.mod (the cli/ module root).
func cliDir(t *testing.T) string {
	t.Helper()
	wd, err := os.Getwd()
	if err != nil {
		t.Fatalf("getwd: %v", err)
	}
	dir := wd
	for {
		if _, err := os.Stat(filepath.Join(dir, "go.mod")); err == nil {
			return dir
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			t.Fatalf("could not locate go.mod (cli module root) from %s", wd)
		}
		dir = parent
	}
}

// repoRoot returns the repository root (parent of the cli/ module dir), where
// scripts/ lives.
func repoRoot(t *testing.T) string {
	t.Helper()
	return filepath.Dir(cliDir(t))
}

package testutils

import (
	"os"
	"path/filepath"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
)

func TestMakeInitializedDDxRoot_WritesConfigYaml(t *testing.T) {
	dir := t.TempDir()

	root := MakeInitializedDDxRoot(t, dir)

	if root != filepath.Join(dir, ddxroot.DirName) {
		t.Fatalf("root = %q, want %q", root, filepath.Join(dir, ddxroot.DirName))
	}
	got, err := os.ReadFile(filepath.Join(root, "config.yaml"))
	if err != nil {
		t.Fatalf("read config.yaml: %v", err)
	}
	if string(got) != "version: \"1.0\"\n" {
		t.Fatalf("config.yaml = %q", got)
	}
}

package testutils

import (
	"os"
	"path/filepath"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
)

// MakeInitializedDDxRoot creates an in-tree .ddx root with the minimal
// config.yaml required for ddxroot.Path to treat dir as an initialized project.
func MakeInitializedDDxRoot(t testing.TB, dir string) string {
	t.Helper()
	root := filepath.Join(dir, ddxroot.DirName)
	if err := os.MkdirAll(root, 0o755); err != nil {
		t.Fatalf("mkdir initialized ddx root: %v", err)
	}
	if err := os.WriteFile(filepath.Join(root, "config.yaml"), []byte("version: \"1.0\"\n"), 0o644); err != nil {
		t.Fatalf("write initialized ddx config: %v", err)
	}
	return root
}

package integration

// concurrent_try_test.go — subprocess integration tests for concurrent ddx try
// invocations as required by TP-021-multi-worker-try-reliability.md.
//
// Three test functions are provided (each satisfying one TP-021 integration AC):
//
//   TestIntegration_ConcurrentTryDistinctBeads_LocalClone
//   TestIntegration_ConcurrentTrySameBead_OneClaimWins
//   TestIntegration_ConcurrentTryPreserveRefsUnique
//
// All three use testutils.BuildDDxBinary, fixture repositories, and the
// deterministic `script` harness with an isolated HOME/XDG_DATA_HOME. None of
// them require network access or external agent CLIs.

import (
	"bytes"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"sync"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/testutils"
)

// subprocessEnvFor builds the minimal isolated subprocess environment used by
// all concurrent-try tests. HOME and XDG_DATA_HOME are set to fresh temp dirs
// so workers do not read real developer config or register with the local
// ddx-server. PATH is stripped to git + standard system directories so agent
// CLIs (codex, claude, gemini) cannot be discovered and daemonised.
func subprocessEnvFor(t *testing.T, bin string) (env []string, home, xdg string) {
	t.Helper()
	gitPath, err := exec.LookPath("git")
	if err != nil {
		t.Fatalf("subprocessEnvFor: locate git binary: %v", err)
	}
	minimalPATH := strings.Join(
		[]string{filepath.Dir(gitPath), filepath.Dir(bin), "/usr/bin", "/bin", "/usr/sbin", "/sbin"},
		string(os.PathListSeparator),
	)
	home = t.TempDir()
	xdg = t.TempDir()
	env = []string{
		"HOME=" + home,
		"XDG_DATA_HOME=" + xdg,
		"PATH=" + minimalPATH,
		"GIT_CONFIG_SYSTEM=/dev/null",
		"GIT_TERMINAL_PROMPT=0",
	}
	return env, home, xdg
}

// spawnTry launches a single `ddx try <beadID>` subprocess and returns the
// started *exec.Cmd with stdout/stderr captured in buf. Callers must call
// cmd.Wait() to collect the exit code and release resources. extraFlags are
// appended to the base flags (e.g. "--from <sha>").
func spawnTry(bin, proj, beadID, harness, directive string, env []string, extraFlags ...string) (*exec.Cmd, *bytes.Buffer) {
	buf := &bytes.Buffer{}
	args := []string{"try", beadID,
		"--harness", harness,
		"--model", directive,
		"--attempt-backend", "local-clone",
		"--no-review", "--no-review-i-know-what-im-doing",
		"--project", proj,
	}
	args = append(args, extraFlags...)
	cmd := exec.Command(bin, args...)
	cmd.Dir = proj
	cmd.Env = env
	cmd.Stdout = buf
	cmd.Stderr = buf
	return cmd, buf
}

// cloneAttemptDirs returns the paths of any lingering .execute-bead-clone-*
// directories under the subprocess's cache area (HOME/.cache/ddx/exec-wt/).
// A subprocess that exits cleanly should remove these; they are only present
// during an active attempt or if cleanup failed.
func cloneAttemptDirs(home string) ([]string, error) {
	cloneRoot := filepath.Join(home, ".cache", "ddx", "exec-wt")
	entries, err := os.ReadDir(cloneRoot)
	if os.IsNotExist(err) {
		return nil, nil
	}
	if err != nil {
		return nil, err
	}
	var found []string
	for _, e := range entries {
		if strings.HasPrefix(e.Name(), ".execute-bead-clone-") {
			found = append(found, filepath.Join(cloneRoot, e.Name()))
		}
	}
	return found, nil
}

// parsePreserveRef extracts the preserve_ref value from ddx try output.
func parsePreserveRef(output string) string {
	const prefix = "preserve_ref: "
	for _, line := range strings.Split(output, "\n") {
		trimmed := strings.TrimSpace(line)
		if strings.HasPrefix(trimmed, prefix) {
			return strings.TrimSpace(strings.TrimPrefix(trimmed, prefix))
		}
	}
	return ""
}

// gitRunIn runs a git command in dir and returns its output, fatally failing t
// on error. env defaults to the current process environment.
func gitRunIn(t *testing.T, dir string, args ...string) string {
	t.Helper()
	cmd := exec.Command("git", append([]string{"-C", dir}, args...)...)
	cmd.Env = append(os.Environ(), "GIT_CONFIG_SYSTEM=/dev/null")
	out, err := cmd.CombinedOutput()
	if err != nil {
		// An "empty commit" is not a test failure.
		if strings.Contains(string(out), "nothing to commit") {
			return string(out)
		}
		t.Fatalf("git %v in %s: %v\n%s", args, dir, err, out)
	}
	return strings.TrimSpace(string(out))
}

// TestIntegration_ConcurrentTryDistinctBeads_LocalClone satisfies TP-021 AC1.
//
// Seeds 8 independent beads and runs 4 concurrent `ddx try <id>` subprocesses
// (each targeting a distinct bead) with the script harness and
// --attempt-backend local-clone. Asserts:
//
//   - all 4 subprocesses exit (success or preserved)
//   - attempt IDs (derived from evidence bundle names) are unique
//   - no lingering .execute-bead-clone-* directories remain after all
//     subprocesses exit
func TestIntegration_ConcurrentTryDistinctBeads_LocalClone(t *testing.T) {
	if testing.Short() {
		t.Skip("integration: spawns ddx try subprocesses")
	}

	bin := testutils.BuildDDxBinary(t)
	t.Setenv("DDX_BIN", bin)
	proj := testutils.NewFixtureRepo(t, "minimal")
	env, home, _ := subprocessEnvFor(t, bin)

	// Suppress auto-materialized paths so the initial tree stays clean.
	if err := appendGitignore(proj, ".agents/", ".claude/", ".ddx/lifecycle-schema.json"); err != nil {
		t.Fatalf("append gitignore: %v", err)
	}
	if err := gitCommitAll(proj, "test: ignore auto-materialized paths"); err != nil {
		t.Fatalf("initial commit: %v", err)
	}

	// Seed 8 independent beads so there is no queue contention.
	const totalBeads = 8
	const concurrentWorkers = 4
	beadIDs, err := createBeads(bin, proj, env, totalBeads, "Concurrent try distinct bead")
	if err != nil {
		t.Fatalf("seed beads: %v", err)
	}
	if err := gitCommitAll(proj, "test: seed distinct beads"); err != nil {
		t.Fatalf("commit beads: %v", err)
	}

	// Directive: simulate an LLM wait outside the lock, then create a file and
	// commit so there are meaningful changes to land.
	directive := filepath.Join(t.TempDir(), "directive.txt")
	if err := os.WriteFile(directive, []byte(
		"sleep-ms 300\n"+
			"create-file out-${DDX_BEAD_ID}.txt done\n"+
			"commit feat: ${DDX_BEAD_ID} done\n"), 0o644); err != nil {
		t.Fatalf("write directive: %v", err)
	}

	// Run concurrentWorkers concurrent ddx try subprocesses against distinct beads.
	type result struct {
		beadID string
		output string
		code   int
	}
	results := make([]result, concurrentWorkers)
	var wg sync.WaitGroup
	for i := 0; i < concurrentWorkers; i++ {
		wg.Add(1)
		go func(idx int) {
			defer wg.Done()
			bid := beadIDs[idx]
			cmd, buf := spawnTry(bin, proj, bid, "script", directive, env)
			if err := cmd.Start(); err != nil {
				t.Errorf("start try for bead %s: %v", bid, err)
				return
			}
			_ = cmd.Wait()
			code := 0
			if cmd.ProcessState != nil {
				code = cmd.ProcessState.ExitCode()
			}
			results[idx] = result{beadID: bid, output: buf.String(), code: code}
		}(i)
	}
	wg.Wait()

	// All 4 subprocesses must have exited (code 0=success, 1=preserved, 2=other).
	// We accept both 0 and 1 because a concurrent land race can preserve a
	// result (another worker on a shared fixture may have advanced the branch).
	// Code 2 (unexpected failure) is always an error.
	for i, r := range results {
		if r.code == 2 {
			t.Errorf("worker %d (bead %s) exited with code 2 (unexpected failure):\n%s", i, r.beadID, r.output)
		}
	}

	// No lingering clone attempt directories after all subprocesses exit.
	lingering, err := cloneAttemptDirs(home)
	if err != nil {
		t.Fatalf("reading clone attempt dirs: %v", err)
	}
	if len(lingering) > 0 {
		t.Errorf("lingering attempt directories after all subprocesses exited:\n%s",
			strings.Join(lingering, "\n"))
	}

	// Attempt IDs must be unique. Collect them from the evidence bundle
	// directory names under .ddx/executions/.
	executionsDir := filepath.Join(ddxroot.JoinProject(proj), agent.ExecuteBeadArtifactDir[len(".ddx/"):])
	entries, err := os.ReadDir(executionsDir)
	if err != nil && !os.IsNotExist(err) {
		t.Fatalf("reading executions dir: %v", err)
	}
	seen := map[string]bool{}
	var attemptIDs []string
	for _, e := range entries {
		if !e.IsDir() {
			continue
		}
		name := e.Name()
		// Evidence bundle dirs are named with the attempt ID (a timestamp-hex string).
		if name == "reviewer-streams" || name == "mirror-index.jsonl" {
			continue
		}
		if seen[name] {
			t.Errorf("duplicate attempt ID in evidence dirs: %s", name)
		}
		seen[name] = true
		attemptIDs = append(attemptIDs, name)
	}
	// At least concurrentWorkers evidence entries must exist (one per attempt).
	if len(attemptIDs) < concurrentWorkers {
		t.Errorf("expected at least %d evidence bundle dirs, found %d", concurrentWorkers, len(attemptIDs))
	}
}

// TestIntegration_ConcurrentTrySameBead_OneClaimWins satisfies TP-021 AC2.
//
// Runs 3 concurrent `ddx try <same-id>` subprocesses against a single bead.
// Asserts:

package integration

import (
	"context"
	"fmt"
	"math"
	"os"
	"os/exec"
	"path/filepath"
	"sort"
	"strings"
	"sync"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/lockmetrics"
	"github.com/DocumentDrivenDX/ddx/internal/testutils"
)

// This file is the wired-in reliability proof for ddx-6650fdc9 / its parent
// scope-locks-to-mutation-window: 5 concurrent `ddx work --watch` workers must
// be able to drain a shared queue while an operator shell issues bead
// create/update/close commands, WITHOUT either side holding .git/index.lock or
// .ddx/.git-tracker.lock long enough to time out the other. The locks are
// scoped to the mutation window only — the harness "LLM wait" (here a script
// `sleep-ms`) happens entirely outside any lock — so p99 hold times stay far
// under the configured caps (DefaultIndexLockCap=10s, DefaultTrackerLockCap=30s
// in internal/lockmetrics/lockcap.go).
//
// The expensive scenario (build a ddx binary, spawn 5 watcher subprocesses and
// 20 operator subprocesses against a fixture repo) runs exactly once via a
// process-wide sync.Once; the four AC-named test functions assert disjoint
// properties of the single captured result.

const (
	workerCount   = 5
	operatorCount = 20
	// workerBeadCount matches the contractual minimum: 5 independent ready
	// beads for 5 workers (the bead's PROPOSED FIX). sleep-ms in the directive
	// keeps each execution's lock-free window open long enough to overlap with
	// the concurrent operator commands.
	workerBeadCount = 5
)

// contentionResult captures everything the four assertions need, so the
// scenario can run once and the fixture can be torn down before later
// assertions execute.
type contentionResult struct {
	indexHoldMS    []float64
	trackerHoldMS  []float64
	operatorOutput []operatorCommand
	workersSpawned int
}

type operatorCommand struct {
	args   string
	output string
	err    error
}

// timedOut reports whether this operator command failed because it could not
// acquire the tracker lock in time (the "tracker lock timeout" error string is
// emitted by lockTimeoutError in internal/agent/tracker_lock.go).
func (c operatorCommand) timedOut() bool {
	return strings.Contains(c.output, "tracker lock timeout")
}

var (
	scenarioOnce   sync.Once
	scenarioResult *contentionResult
	scenarioErr    error
)

// contentionScenario runs the multi-worker scenario at most once per process
// and returns the captured result. Heavy integration work is skipped under
// `go test -short`.
func contentionScenario(t *testing.T) *contentionResult {
	t.Helper()
	if testing.Short() {
		t.Skip("integration test: spawns ddx work --watch subprocesses")
	}
	scenarioOnce.Do(func() {
		scenarioResult, scenarioErr = runContentionScenario(t)
	})
	if scenarioErr != nil {
		t.Fatalf("multi-worker lock-contention scenario failed: %v", scenarioErr)
	}
	return scenarioResult
}

// TestIntegration_MultiWorkerLockContention_5Workers proves the scenario runs
// to completion: 5 `ddx work --watch` worker processes were spawned and all 20
// operator bead commands executed.
func TestIntegration_MultiWorkerLockContention_5Workers(t *testing.T) {
	res := contentionScenario(t)
	if res.workersSpawned != workerCount {
		t.Fatalf("expected %d ddx work --watch worker processes, spawned %d", workerCount, res.workersSpawned)
	}
	if len(res.operatorOutput) != operatorCount {
		t.Fatalf("expected %d operator bead commands to run, got %d", operatorCount, len(res.operatorOutput))
	}
	// At least one lock acquisition must have been observed, otherwise the p99
	// assertions below would be vacuously true.
	if len(res.indexHoldMS) == 0 && len(res.trackerHoldMS) == 0 {
		t.Fatal("no lock acquisitions recorded; workers did not exercise the instrumented lock seams")
	}
}

// TestIntegration_MultiWorkerLockContention_P99IndexLockUnderCap asserts the
// p99 .git/index.lock hold time across all acquisitions is under the cap.
func TestIntegration_MultiWorkerLockContention_P99IndexLockUnderCap(t *testing.T) {
	res := contentionScenario(t)
	if len(res.indexHoldMS) == 0 {
		t.Fatal("no index.lock acquisitions recorded")
	}
	p99 := percentile(res.indexHoldMS, 0.99)
	capMS := float64(lockmetrics.DefaultIndexLockCap.Milliseconds())
	if p99 >= capMS {
		t.Fatalf("p99 index.lock hold %.0fms >= cap %.0fms (n=%d, max=%.0fms)",
			p99, capMS, len(res.indexHoldMS), maxFloat(res.indexHoldMS))
	}
}

// TestIntegration_MultiWorkerLockContention_P99TrackerLockUnderCap asserts the
// p99 .ddx/.git-tracker.lock hold time across all acquisitions is under the cap.
func TestIntegration_MultiWorkerLockContention_P99TrackerLockUnderCap(t *testing.T) {
	res := contentionScenario(t)
	if len(res.trackerHoldMS) == 0 {
		t.Fatal("no tracker.lock acquisitions recorded")
	}
	p99 := percentile(res.trackerHoldMS, 0.99)
	capMS := float64(lockmetrics.DefaultTrackerLockCap.Milliseconds())
	if p99 >= capMS {
		t.Fatalf("p99 tracker.lock hold %.0fms >= cap %.0fms (n=%d, max=%.0fms)",
			p99, capMS, len(res.trackerHoldMS), maxFloat(res.trackerHoldMS))
	}
}

// TestIntegration_MultiWorkerLockContention_NoOperatorTimeouts asserts that no
// operator-issued bead command failed with a tracker-lock timeout.
func TestIntegration_MultiWorkerLockContention_NoOperatorTimeouts(t *testing.T) {
	res := contentionScenario(t)
	var timedOut []string
	for _, c := range res.operatorOutput {
		if c.timedOut() {
			timedOut = append(timedOut, fmt.Sprintf("`ddx bead %s`: %s", c.args, strings.TrimSpace(c.output)))
		}
	}
	if len(timedOut) > 0 {
		t.Fatalf("%d operator command(s) failed with tracker lock timeout:\n%s",
			len(timedOut), strings.Join(timedOut, "\n"))
	}
}

// TestDocs_LockContractSectionPresent asserts the repo-root AGENTS.md documents
// the lock-lifetime contract this test file enforces: the "Lock Lifetime
// Contract" heading plus the configured caps (10s/30s) and the violation
// evidence file name. This keeps the contributor-facing doc in lockstep with
// the enforcement so future changes do not silently regress it.
func TestDocs_LockContractSectionPresent(t *testing.T) {
	wd, err := os.Getwd()
	if err != nil {
		t.Fatalf("getwd: %v", err)
	}
	// Walk up to the cli/ module root (go.mod); AGENTS.md is its repo-root parent.
	dir := wd
	cliRoot := ""
	for i := 0; i < 8; i++ {
		if _, statErr := os.Stat(filepath.Join(dir, "go.mod")); statErr == nil {
			cliRoot = dir
			break
		}
		dir = filepath.Dir(dir)
	}
	if cliRoot == "" {
		t.Fatalf("could not locate cli/ module root from %s", wd)
	}
	agentsPath := filepath.Join(filepath.Dir(cliRoot), "AGENTS.md")
	data, err := os.ReadFile(agentsPath)
	if err != nil {
		t.Fatalf("read %s: %v", agentsPath, err)
	}
	content := string(data)
	for _, want := range []string{
