package testutils

import (
	"bufio"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"testing"
)

func TestNewFixtureRepo_CachesPerProfileAndCopiesIsolation(t *testing.T) {
	cacheRoot := t.TempDir()

	prevCacheRoot := fixtureRepoCacheRootOverride
	prevBuilder := buildFixtureRepoTemplateFn
	fixtureRepoCacheRootOverride = cacheRoot
	t.Cleanup(func() {
		fixtureRepoCacheRootOverride = prevCacheRoot
		buildFixtureRepoTemplateFn = prevBuilder
	})

	var mu sync.Mutex
	buildCounts := map[string]int{}
	buildFixtureRepoTemplateFn = func(t *testing.T, dest, profile string) error {
		mu.Lock()
		buildCounts[profile]++
		mu.Unlock()
		return prevBuilder(t, dest, profile)
	}

	t.Setenv("DDX_BIN", BuildDDxBinary(t))

	minimal1 := NewFixtureRepo(t, "minimal")
	minimal2 := NewFixtureRepo(t, "minimal")
	standard1 := NewFixtureRepo(t, "standard")
	standard2 := NewFixtureRepo(t, "standard")

	marker1 := filepath.Join(minimal1, "marker.txt")
	if err := os.WriteFile(marker1, []byte("one"), 0o644); err != nil {
		t.Fatalf("write marker in first minimal fixture: %v", err)
	}
	if _, err := os.Stat(filepath.Join(minimal2, "marker.txt")); !os.IsNotExist(err) {
		t.Fatalf("second minimal fixture unexpectedly saw first fixture marker: %v", err)
	}

	standardMarker := filepath.Join(standard1, "marker.txt")
	if err := os.WriteFile(standardMarker, []byte("one"), 0o644); err != nil {
		t.Fatalf("write marker in first standard fixture: %v", err)
	}
	if _, err := os.Stat(filepath.Join(standard2, "marker.txt")); !os.IsNotExist(err) {
		t.Fatalf("second standard fixture unexpectedly saw first fixture marker: %v", err)
	}

	if got := countNonEmptyLines(t, filepath.Join(standard1, ".ddx", "beads.jsonl")); got != 5 {
		t.Fatalf("standard fixture bead count = %d, want 5", got)
	}
	if got := countNonEmptyLines(t, filepath.Join(standard2, ".ddx", "beads.jsonl")); got != 5 {
		t.Fatalf("copied standard fixture bead count = %d, want 5", got)
	}

	mu.Lock()
	defer mu.Unlock()
	if got, want := buildCounts["minimal"], 1; got != want {
		t.Fatalf("build count for minimal = %d, want %d", got, want)
	}
	if got, want := buildCounts["standard"], 1; got != want {
		t.Fatalf("build count for standard = %d, want %d", got, want)
	}
}

func countNonEmptyLines(t *testing.T, path string) int {
	t.Helper()

	f, err := os.Open(path)
	if err != nil {
		t.Fatalf("open %s: %v", path, err)
	}
	defer f.Close()

	scanner := bufio.NewScanner(f)
	count := 0
	for scanner.Scan() {
		if strings.TrimSpace(scanner.Text()) != "" {
			count++
		}
	}
	if err := scanner.Err(); err != nil {
		t.Fatalf("scan %s: %v", path, err)
	}
	return count
}
